<?php
declare(strict_types=1);
if(PHP_OS_FAMILY!=='Linux'||function_exists('posix_geteuid')&&posix_geteuid()!==0){fwrite(STDERR,"Run as root on Linux.\n");exit(1);}
require dirname(__DIR__).'/src/bootstrap.php';
$rows=db()->query("SELECT d.*,s.id site_id FROM site_domains d JOIN sites s ON s.id=d.site_id WHERE d.status='verified' AND d.tls_status<>'active'")->fetchAll();
foreach($rows as $d){$host=strtolower((string)$d['hostname']);if(!preg_match('/^(?:[a-z0-9](?:[a-z0-9-]{0,61}[a-z0-9])?\.)+[a-z]{2,63}$/',$host))continue;$id=(int)$d['id'];$conf="<VirtualHost *:80>\n ServerName $host\n DocumentRoot /var/www/opencrm/public\n <Directory /var/www/opencrm/public>\n  AllowOverride All\n  Require all granted\n </Directory>\n</VirtualHost>\n";$file='/etc/apache2/sites-available/opencrm-domain-'.$id.'.conf';file_put_contents($file,$conf);exec('a2ensite '.escapeshellarg(basename($file)).' 2>&1',$out,$code);exec('apachectl configtest 2>&1',$test,$testCode);if($testCode!==0){db()->prepare("UPDATE site_domains SET tls_status='failed' WHERE id=?")->execute([$id]);continue;}exec('systemctl reload apache2 2>&1');$email=app_setting('mail_from_email','admin@'.$host);$cmd='certbot --apache --non-interactive --agree-tos --redirect -m '.escapeshellarg($email).' -d '.escapeshellarg($host).' 2>&1';exec($cmd,$cert,$certCode);db()->prepare("UPDATE site_domains SET status=?,tls_status=?,last_checked_at=NOW(),is_primary=IF(?='active',is_primary,is_primary) WHERE id=?")->execute([$certCode===0?'active':'verified',$certCode===0?'active':'failed',$certCode===0?'active':'failed',$id]);app_log($certCode===0?'info':'error','Custom domain TLS provisioning',['domain'=>$host,'exit_code'=>$certCode,'output'=>array_slice($cert,-5)]);}
echo 'Processed '.count($rows)." domain(s).\n";
